// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { QrCode, CheckCircle, ChevronRight, Calendar } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays } from 'date-fns'
import Etiqueta from './Etiqueta'
import { QRCodeSVG as QRCode } from 'qrcode.react'

export default function TelaEsterilizacao() {
  // estados principais
  const [step, setStep] = useState(1)                 // controla a etapa do wizard
  const [tipoOp, setTipoOp] = useState(null)          // 'entrada' ou 'saida'
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoInfo, setAlunoInfo] = useState(null)    // { nome, ra }
  const [historico, setHistorico] = useState([])
  const [codigo, setCodigo] = useState('')
  const [materiais, setMateriais] = useState([])
  const [printEnabled, setPrintEnabled] = useState(false)
  const [printedIds, setPrintedIds] = useState(new Set())
  const [printData, setPrintData] = useState(null)
  const componentRef = useRef(null)
  const datePickerRef = useRef(null)
  const [filterDate, setFilterDate] = useState('')
  const [searchTerm, setSearchTerm] = useState('')

  // passo 1: escolher operação
  const handleTipoOp = (t) => {
    setTipoOp(t)
    setStep(2)
  }

  // busca histórico após validar aluno
  const fetchHistory = useCallback(() => {
    if (!alunoInfo) return
    axios.get('/api/movimentacoes')
      .then(res => {
        const hoje = new Date()
        const from = subDays(hoje, 30).toISOString().slice(0, 10)
        setHistorico(res.data.filter(m =>
          m.alunoNome === alunoInfo.nome &&
          new Date(m.criado_em).toISOString().slice(0,10) >= from
        ))
      })
      .catch(() => setHistorico([]))
  }, [alunoInfo])

  // passo 2: validar PIN
  const validarPin = () => {
    if (alunoPin.length !== 4) {
      return toast.warn('PIN deve ter 4 dígitos.')
    }
    axios.get(`/api/alunos/pin/${alunoPin}`)
      .then(res => {
        setAlunoInfo({ nome: res.data.nome, ra: res.data.ra })
        fetchHistory()
        setStep(3)
      })
      .catch(() => toast.error('PIN não encontrado.'))
  }

  // passo 3 → 4: adicionar materiais
  const addMaterial = () => {
    if (!codigo.trim()) return
    axios.get(`/api/caixas?busca=${codigo}`)
      .then(res => {
        const item = res.data[0]
        setMateriais(m => [...m, item])
        setCodigo('')
      })
      .catch(() => toast.error('Material não encontrado.'))
  }

  // passo 4: confirmar operação
  const handleConfirm = () => {
    axios.post(`/api/movimentacoes/${tipoOp}`, {
      aluno_pin: alunoPin,
      caixas: materiais.map(m => m.id)
    })
    .then(() => {
      toast.success(`${tipoOp === 'entrada' ? 'Entrada' : 'Saída'} confirmada!`)
      if (printEnabled) setStep(5)
      else resetWizard()
    })
    .catch(() => toast.error('Erro ao confirmar.'))
  }

  // passo 5: imprimir etiquetas
  const handlePrint = (m) => {
    setPrintData({ ...m, alunoNome: alunoInfo.nome })
    setPrintedIds(ids => new Set(ids).add(m.id))
  }

  const resetWizard = () => {
    setStep(1)
    setTipoOp(null)
    setAlunoPin('')
    setAlunoInfo(null)
    setMateriais([])
    setPrintEnabled(false)
    setPrintedIds(new Set())
  }

  // efeito para disparar janela de impressão
  useEffect(() => {
    if (!printData) return
    const html = `
      <html>
        <head>
          <style>body{padding:8mm;font-family:sans-serif}</style>
        </head>
        <body>
          <h2>${printData.alunoNome}</h2>
          <h3>Caixa: ${printData.nome || printData.caixaNome}</h3>
          ${componentRef.current?.innerHTML}
        </body>
      </html>`
    const pw = window.open('', '_blank','width=400,height=300')
    pw.document.write(html)
    pw.document.close()
    pw.focus()
    pw.print()
    setPrintData(null)
  }, [printData])

  return (
    <div className="max-w-xl mx-auto p-6 space-y-6">
      {/* Passo 1 */}
      {step === 1 && (
        <div className="space-y-4 text-center">
          <h2 className="text-2xl font-bold">Esterilização</h2>
          <button onClick={() => handleTipoOp('entrada')}
            className="w-full py-2 bg-green-600 text-white rounded">ENTRADA</button>
          <button onClick={() => handleTipoOp('saida')}
            className="w-full py-2 bg-red-600 text-white rounded">SAÍDA</button>
        </div>
      )}

      {/* Passo 2 */}
      {step === 2 && (
        <div className="space-y-4">
          <h3 className="font-semibold">Informe seu PIN</h3>
          <input
            type="password"
            maxLength={4}
            value={alunoPin}
            onChange={e => setAlunoPin(e.target.value.replace(/\D/g, ''))}
            className="w-full border px-3 py-2 rounded"
          />
          <button onClick={validarPin}
            className="w-full py-2 bg-blue-600 text-white rounded">Avançar</button>
        </div>
      )}

      {/* Passo 3 */}
      {step === 3 && alunoInfo && (
        <div className="space-y-4">
          <h3>Aluno: {alunoInfo.nome} (RA: {alunoInfo.ra})</h3>
          <h4 className="font-semibold">Histórico (30 dias)</h4>
          <ul className="list-disc ml-5 space-y-1 text-sm">
            {historico.map(h => (
              <li key={h.id}>
                {h.caixaNome} – {h.tipo} em {new Date(h.criado_em).toLocaleDateString()}
              </li>
            ))}
          </ul>
          <button onClick={() => setStep(4)}
            className="w-full py-2 bg-blue-600 text-white rounded flex justify-center items-center gap-2">
            Avançar <ChevronRight size={18}/>
          </button>
        </div>
      )}

      {/* Passo 4 */}
      {step === 4 && (
        <div className="space-y-4">
          <h3 className="font-semibold">{tipoOp?.toUpperCase()}</h3>
          <div className="flex gap-2">
            <input
              type="text"
              placeholder="Código ou nome"
              value={codigo}
              onChange={e => setCodigo(e.target.value)}
              className="flex-1 border px-3 py-2 rounded"
            />
            <button onClick={addMaterial}
              className="px-4 bg-[#1A1C2C] text-white rounded">+</button>
          </div>
          <ul className="list-disc ml-5 space-y-1">
            {materiais.map(m => (
              <li key={m.id}>{m.nome}</li>
            ))}
          </ul>
          <label className="inline-flex items-center gap-2">
            <input
              type="checkbox"
              checked={printEnabled}
              onChange={e => setPrintEnabled(e.target.checked)}
            />
            <span>Imprimir etiquetas?</span>
          </label>
          <button onClick={handleConfirm}
            className="w-full py-2 bg-green-600 text-white rounded">
            Confirmar {tipoOp}
          </button>
        </div>
      )}

      {/* Passo 5 */}
      {step === 5 && (
        <div className="space-y-4">
          <h3 className="font-semibold">Impressão de Etiquetas</h3>
          <div className="space-y-2">
            {materiais.map(m => (
              <div key={m.id} className="flex items-center justify-between bg-gray-50 p-2 rounded">
                <span>{m.nome}</span>
                {printedIds.has(m.id) ? (
                  <CheckCircle size={18} className="text-green-600"/>
                ) : (
                  <button onClick={() => handlePrint(m)} title="Imprimir">
                    <QrCode size={18}/>
                  </button>
                )}
              </div>
            ))}
          </div>
          <button onClick={() => materiais.forEach(m => {
              if (!printedIds.has(m.id)) handlePrint(m)
            })}
            className="w-full py-2 bg-blue-600 text-white rounded">
            Imprimir todos
          </button>
          <button onClick={resetWizard}
            className="w-full py-2 bg-gray-300 text-black rounded">
            Finalizar
          </button>
        </div>
      )}
    </div>
  )
}
